-- ============================================
-- AL Governador: Renan Filho legislacao executiva parcial + CEAPS 2026; JHC timeline eleitoral
-- Fonte unica: documentação interna
-- Artefatos:
--   fonte interna de curadoria
--   fonte interna de curadoria
--
-- Observacao: o inventario SAPL ainda e parcial, porque 92 normas candidatas nao tiveram PDF textual parseavel
-- ou texto_integral disponivel. As linhas abaixo entram somente quando o PDF textual contem assinatura nominal
-- de JOSÉ RENAN VASCONCELOS CALHEIROS FILHO e a data normalizada fica dentro do cutoff de mandato.
-- ============================================

DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM candidatos WHERE slug = 'renan-filho' AND publicavel = true) THEN
    RAISE EXCEPTION 'renan-filho nao encontrado ou nao publicavel';
  END IF;
  IF NOT EXISTS (SELECT 1 FROM candidatos WHERE slug = 'jhc' AND publicavel = true) THEN
    RAISE EXCEPTION 'jhc nao encontrado ou nao publicavel';
  END IF;
END $$;

-- Normaliza eventos TSE duplicados de JHC como eventos eleitorais, preservando o mandato manual curado.
UPDATE historico_politico
SET tipo_evento = 'candidatura',
    periodo_fim = periodo_inicio,
    observacoes = CASE
      WHEN observacoes ILIKE '%Linha TSE mantida como evento eleitoral%' THEN observacoes
      ELSE CONCAT_WS(' ', observacoes, 'Linha TSE mantida como evento eleitoral; mandato materializado em linha manual curada.')
    END
WHERE id IN (
  '853c9d68-9ad1-47e9-af98-cc1cd1d4b700'::uuid,
  '8baeae22-13ab-4960-a2ee-f61913add740'::uuid,
  'fda229aa-9ca9-427d-ba0c-739cf556edf6'::uuid
)
  AND tipo_evento = 'mandato';

