WITH target AS (
  SELECT
    c.id AS candidato_id,
    seed.*,
    (
      SELECT hp.id
      FROM historico_politico hp
      WHERE hp.candidato_id = c.id
        AND hp.tipo_evento = 'mandato'
        AND UPPER(COALESCE(hp.estado, '')) = 'AL'
        AND (hp.cargo ILIKE '%Governador%' OR hp.cargo_canonico = 'Governador')
        AND COALESCE(hp.periodo_inicio, 9999) <= EXTRACT(YEAR FROM seed.data_norma::date)::int
        AND COALESCE(hp.periodo_fim, 9999) >= EXTRACT(YEAR FROM seed.data_norma::date)::int
      ORDER BY hp.periodo_inicio DESC NULLS LAST, hp.id
      LIMIT 1
    ) AS historico_politico_id
  FROM candidatos c
  CROSS JOIN _seed_renan_filho_al_sapl_lme seed
  WHERE c.slug = 'renan-filho' AND c.publicavel = true
)
INSERT INTO legislacao_mandato_executivo (
  candidato_id, historico_politico_id, tipo_relacao, esfera, uf_norma, tipo_norma, numero, ano,
  data_norma, ementa, signatario, autoridade_papel, fonte_primaria_url, fonte_primaria_titulo,
  fonte_tramitacao_url, identificador_fonte, metadata
)
SELECT
  target.candidato_id, target.historico_politico_id, target.tipo_relacao, target.esfera, target.uf_norma,
  target.tipo_norma, target.numero, target.ano, target.data_norma::date, target.ementa, target.signatario,
  target.autoridade_papel, target.fonte_primaria_url, target.fonte_primaria_titulo, target.fonte_tramitacao_url,
  target.identificador_fonte, target.metadata
FROM target
WHERE target.historico_politico_id IS NOT NULL
  AND NOT EXISTS (
    SELECT 1 FROM legislacao_mandato_executivo lme
    WHERE lme.candidato_id = target.candidato_id
      AND lme.identificador_fonte = target.identificador_fonte
  );

CREATE TEMP TABLE _seed_renan_filho_ceaps_gastos ON COMMIT DROP AS
SELECT *
FROM (
VALUES
  (2026, 84912.43, '[{"categoria":"Passagens aéreas, aquáticas e terrestres nacionais","valor":45479.04},{"categoria":"Contratação de consultorias, assessorias, pesquisas, trabalhos técnicos e outros serviços de apoio ao exercício do mandato parlamentar","valor":37933.39},{"categoria":"Divulgação da atividade parlamentar","valor":1500}]'::jsonb, '[{"fornecedor":"Aerotur Serviços","categoria":"Passagens aéreas, aquáticas e terrestres nacionais","valor":6293.03,"documento":"2301400175","data":"07/04/2026","cod_documento":"2287777"},{"fornecedor":"Aerotur Serviços","categoria":"Passagens aéreas, aquáticas e terrestres nacionais","valor":3752.31,"documento":"2301505898","data":"09/04/2026","cod_documento":"2287779"},{"fornecedor":"AGM VIAGENS &TURISMO","categoria":"Passagens aéreas, aquáticas e terrestres nacionais","valor":3752.09,"documento":"WOKYXR","data":"01/04/2026","cod_documento":"2287024"},{"fornecedor":"Aerotur Serviços","categoria":"Passagens aéreas, aquáticas e terrestres nacionais","valor":3732.83,"documento":"2301560113","data":"09/04/2026","cod_documento":"2287781"},{"fornecedor":"Aerotur Serviços","categoria":"Passagens aéreas, aquáticas e terrestres nacionais","valor":3597.61,"documento":"2301046204","data":"02/04/2026","cod_documento":"2287778"}]'::jsonb, 'Senado CEAPS', '{"source":"Senado CEAPS CSV","data_real":true,"fluxo":"candidate-completion-status-html-workflow","curation_batch_id":"al-governador-fechamento-parcial-20260703","coverage_id":"renan-filho-senado-ceaps-2026-20260703","coverage_scope":"inventario_ceaps_ano_disponivel_2026","row_count":43,"source_urls":["https://www.senado.leg.br/transparencia/LAI/verba/despesa_ceaps_2026.csv"],"ultima_atualizacao":["03/07/2026 02:03"]}'::jsonb)
) AS v(ano, total_gasto, detalhamento, gastos_destaque, fonte, metadata);

DELETE FROM gastos_parlamentares gp
USING candidatos c
WHERE gp.candidato_id = c.id
  AND c.slug = 'renan-filho'
  AND gp.fonte = 'Senado CEAPS'
  AND gp.ano IN (SELECT ano FROM _seed_renan_filho_ceaps_gastos);

INSERT INTO gastos_parlamentares (candidato_id, ano, total_gasto, detalhamento, gastos_destaque, fonte)
SELECT c.id, seed.ano, seed.total_gasto, seed.detalhamento, seed.gastos_destaque, seed.fonte
FROM candidatos c
CROSS JOIN _seed_renan_filho_ceaps_gastos seed
WHERE c.slug = 'renan-filho' AND c.publicavel = true;

DO $$
DECLARE
  renan_id uuid;
  scope_count int;
  gastos_count int;
  jhc_dup_mandatos int;
BEGIN
  SELECT id INTO renan_id FROM candidatos WHERE slug = 'renan-filho' AND publicavel = true;

  SELECT count(*) INTO scope_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = renan_id
    AND metadata ->> 'coverage_id' = 'renan-filho-al-sapl-pdfs-assinados-2015-2022-20260703';
  IF scope_count <> 640 THEN
    RAISE EXCEPTION 'renan-filho LME SAPL: esperado 640, encontrado %', scope_count;
  END IF;

  SELECT count(*) INTO gastos_count
  FROM gastos_parlamentares gp
  WHERE gp.candidato_id = renan_id
    AND gp.fonte = 'Senado CEAPS'
    AND gp.ano = 2026;
  IF gastos_count <> 1 THEN
    RAISE EXCEPTION 'renan-filho CEAPS 2026: esperado 1 row, encontrado %', gastos_count;
  END IF;

  SELECT count(*) INTO jhc_dup_mandatos
  FROM historico_politico
  WHERE id IN (
    '853c9d68-9ad1-47e9-af98-cc1cd1d4b700'::uuid,
    '8baeae22-13ab-4960-a2ee-f61913add740'::uuid,
    'fda229aa-9ca9-427d-ba0c-739cf556edf6'::uuid
  )
    AND tipo_evento = 'mandato';
  IF jhc_dup_mandatos <> 0 THEN
    RAISE EXCEPTION 'JHC timeline: linhas TSE duplicadas ainda marcadas como mandato: %', jhc_dup_mandatos;
  END IF;
END $$;
